enum Command {
    Uppercase,
    Trim,
    Append(usize),
}

mod my_module {
    use super::Command;

    pub fn transformer(input: Vec<(String, Command)>) -> Vec<String> {
        let mut output: Vec<String> = vec![];
        for (string, command) in input {
            let result = match command {
                Command::Uppercase => string.to_uppercase(),
                Command::Trim => string.trim().to_string(),
                Command::Append(n) => {
                    let mut s = string;
                    for _ in 0..n {
                        s.push_str("bar");
                    }
                    s
                }
            };
            output.push(result);
        }
        output
    }
}

fn main() {
    let input = vec![
        ("hello".to_string(), Command::Uppercase),
        (" all hail Rust!  ".to_string(), Command::Trim),
        ("foo".to_string(), Command::Append(3)),
    ];
    let output = my_module::transformer(input);
    assert_eq!(output[0], "HELLO");
    assert_eq!(output[1], "all hail Rust!");
    assert_eq!(output[2], "foobarbarbar");
    println!("Quiz 2 passed!");
}
